import { _decorator, Component } from "cc";
import * as fgui from "../../Plugins/FairyGUI/fairygui.mjs";

const { ccclass } = _decorator;

@ccclass("UIManager")
export class UIManager extends Component {
  start() {
    // Load the exported FairyGUI package
    fgui.UIPackage.loadPackage("FGUI", () => {
      // Create the UI component from the package
      const view = fgui.UIPackage.createObject("FGUI", "Main").asCom;

      // Add it to the screen
      fgui.GRoot.inst.addChild(view);
    });
  }
}
